"use strict";(self.webpackChunkarduino_edukit_algerie=self.webpackChunkarduino_edukit_algerie||[]).push([[4132],{7630:(n,e,t)=>{t.r(e),t.d(e,{assets:()=>s,contentTitle:()=>a,default:()=>p,frontMatter:()=>l,metadata:()=>i,toc:()=>d});const i=JSON.parse('{"id":"projet-gps-tracker/code","title":"Code Arduino \u2014 GPS Tracker","description":"---","source":"@site/docs/projet-gps-tracker/code.md","sourceDirName":"projet-gps-tracker","slug":"/projet-gps-tracker/code","permalink":"/projets_ecoles/docs/projet-gps-tracker/code","draft":false,"unlisted":false,"editUrl":"https://github.com/arduino-edu-algerie/arduino-edukit/tree/main/docs/projet-gps-tracker/code.md","tags":[],"version":"current","lastUpdatedBy":"jodokfehlmann","lastUpdatedAt":1776666976000,"frontMatter":{"id":"code","title":"Code Arduino \u2014 GPS Tracker","sidebar_label":"\ud83d\udcbb Code"},"sidebar":"tutorialSidebar","previous":{"title":"\ud83d\udd0c C\xe2blage","permalink":"/projets_ecoles/docs/projet-gps-tracker/cablage"},"next":{"title":"\ud83d\udcdd Exercices","permalink":"/projets_ecoles/docs/projet-gps-tracker/exercices"}}');var r=t(4848),o=t(8453);const l={id:"code",title:"Code Arduino \u2014 GPS Tracker",sidebar_label:"\ud83d\udcbb Code"},a="\ud83d\udcbb Code Arduino \u2014 GPS Tracker",s={},d=[{value:"\ud83d\udccd Visualiser ta trace sur Google Earth",id:"-visualiser-ta-trace-sur-google-earth",level:2}];function c(n){const e={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",hr:"hr",li:"li",ol:"ol",p:"p",pre:"pre",strong:"strong",...(0,o.R)(),...n.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(e.header,{children:(0,r.jsx)(e.h1,{id:"-code-arduino--gps-tracker",children:"\ud83d\udcbb Code Arduino \u2014 GPS Tracker"})}),"\n",(0,r.jsx)(e.pre,{children:(0,r.jsx)(e.code,{className:"language-cpp",metastring:'title="gps_tracker.ino"',children:'// ============================================\n// Arduino EduKit Alg\xe9rie \u2014 GPS Tracker\n// Version 1.0 \u2014 Licence MIT\n// ============================================\n\n#include <TinyGPS++.h>\n#include <SoftwareSerial.h>\n#include <Wire.h>\n#include <Adafruit_SSD1306.h>\n#include <Adafruit_BMP280.h>\n#include <RTClib.h>\n#include <SD.h>\n\n// === BROCHES ===\n#define GPS_RX      4\n#define GPS_TX      5\n#define SD_CS       10\n#define LED_STATUT  3\n#define BTN_WAYPOINT 2\n\n// === OBJETS ===\nTinyGPSPlus       gps;\nSoftwareSerial    gpsSerial(GPS_RX, GPS_TX);\nAdafruit_SSD1306  oled(128, 64, &Wire, -1);\nAdafruit_BMP280   bmp;\nRTC_DS3231        rtc;\n\n// === VARIABLES ===\nString nomFichier  = "";\nint    nbPoints    = 0;\nint    nbWaypoints = 0;\nbool   sdOk        = false;\nfloat  distTotale  = 0;\nfloat  latPrec = 0, lonPrec = 0;\nunsigned long dernierEnreg = 0;\n#define INTERVALLE_ENREG 5000  // 1 point toutes les 5 secondes\n\n// ============================================\n// FORMAT GPX \u2014 standard universel de traces GPS\n// ============================================\n\nvoid creerFichierGPX() {\n  DateTime now = rtc.now();\n  char buf[20];\n  sprintf(buf, "TR%02d%02d%02d.gpx", now.day(), now.hour(), now.minute());\n  nomFichier = String(buf);\n\n  File f = SD.open(nomFichier, FILE_WRITE);\n  if (f) {\n    f.println("<?xml version=\\"1.0\\" encoding=\\"UTF-8\\"?>");\n    f.println("<gpx version=\\"1.1\\" creator=\\"Arduino EduKit\\">");\n    f.println("  <trk><name>Trace EduKit</name><trkseg>");\n    f.close();\n    sdOk = true;\n    Serial.print("Fichier GPX: "); Serial.println(nomFichier);\n  }\n}\n\nvoid ajouterPointGPX(float lat, float lon, float alt, DateTime& now) {\n  File f = SD.open(nomFichier, FILE_WRITE);\n  if (f) {\n    char ligne[120];\n    sprintf(ligne,\n      "    <trkpt lat=\\"%.6f\\" lon=\\"%.6f\\"><ele>%.1f</ele>"\n      "<time>%04d-%02d-%02dT%02d:%02d:%02dZ</time></trkpt>",\n      lat, lon, alt,\n      now.year(), now.month(), now.day(),\n      now.hour(), now.minute(), now.second()\n    );\n    f.println(ligne);\n    f.close();\n    nbPoints++;\n  }\n}\n\nvoid ajouterWaypoint(float lat, float lon, int num) {\n  File f = SD.open(nomFichier, FILE_WRITE);\n  if (f) {\n    char ligne[100];\n    sprintf(ligne,\n      "  <wpt lat=\\"%.6f\\" lon=\\"%.6f\\"><name>WP%d</name></wpt>",\n      lat, lon, num\n    );\n    f.println(ligne);\n    f.close();\n    nbWaypoints++;\n  }\n}\n\nvoid fermerFichierGPX() {\n  File f = SD.open(nomFichier, FILE_WRITE);\n  if (f) {\n    f.println("  </trkseg></trk>");\n    f.println("</gpx>");\n    f.close();\n  }\n}\n\n// ============================================\n// CALCUL DE DISTANCE (Formule Haversine)\n// ============================================\n\nfloat distanceMetres(float lat1, float lon1, float lat2, float lon2) {\n  float R = 6371000; // Rayon Terre en m\xe8tres\n  float dLat = (lat2 - lat1) * PI / 180.0;\n  float dLon = (lon2 - lon1) * PI / 180.0;\n  float a = sin(dLat/2) * sin(dLat/2) +\n            cos(lat1 * PI/180.0) * cos(lat2 * PI/180.0) *\n            sin(dLon/2) * sin(dLon/2);\n  return R * 2 * atan2(sqrt(a), sqrt(1-a));\n}\n\n// ============================================\n// AFFICHAGE OLED\n// ============================================\n\nvoid afficherOLED() {\n  oled.clearDisplay();\n  oled.setTextColor(WHITE);\n\n  if (!gps.location.isValid()) {\n    // En attente de fix GPS\n    oled.setTextSize(1);\n    oled.setCursor(0, 0);  oled.print("Recherche GPS...");\n    oled.setCursor(0, 16); oled.print("Satellites: ");\n    oled.print(gps.satellites.value());\n    oled.setCursor(0, 32); oled.print("Reste dehors");\n    oled.setCursor(0, 48); oled.print("vue sur le ciel");\n  } else {\n    // Fix obtenu \u2014 afficher donn\xe9es\n    oled.setTextSize(1);\n\n    // Coordonn\xe9es\n    oled.setCursor(0, 0);\n    oled.print("Lat: "); oled.print(gps.location.lat(), 5);\n    oled.setCursor(0, 10);\n    oled.print("Lon: "); oled.print(gps.location.lng(), 5);\n\n    // Vitesse et altitude\n    oled.setCursor(0, 22);\n    oled.print("Alt: "); oled.print(bmp.readAltitude(1013.25), 0); oled.print("m");\n    oled.setCursor(64, 22);\n    oled.print("Vit: "); oled.print(gps.speed.kmph(), 1); oled.print("km/h");\n\n    // Distance totale\n    oled.setCursor(0, 34);\n    oled.print("Dist: ");\n    if (distTotale >= 1000) {\n      oled.print(distTotale/1000, 2); oled.print("km");\n    } else {\n      oled.print(distTotale, 0); oled.print("m");\n    }\n\n    // Statut SD et nb points\n    oled.setCursor(0, 46);\n    oled.print(sdOk ? "SD:OK" : "SD:ERR");\n    oled.print(" Pts:"); oled.print(nbPoints);\n    oled.print(" WP:"); oled.print(nbWaypoints);\n\n    // Sats\n    oled.setCursor(0, 56);\n    oled.print("Sats:"); oled.print(gps.satellites.value());\n    oled.print(" HDOP:"); oled.print(gps.hdop.value()/100.0, 1);\n  }\n\n  oled.display();\n}\n\n// ============================================\n// SETUP & LOOP\n// ============================================\n\nvoid setup() {\n  Serial.begin(115200);\n  gpsSerial.begin(9600);\n  Wire.begin();\n\n  // OLED\n  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);\n  oled.clearDisplay();\n  oled.setTextColor(WHITE);\n  oled.setTextSize(2);\n  oled.setCursor(10, 10); oled.print("GPS");\n  oled.setCursor(10, 30); oled.print("Tracker");\n  oled.display();\n  delay(2000);\n\n  // BMP280 et RTC\n  bmp.begin(0x76);\n  rtc.begin();\n\n  // Bouton waypoint\n  pinMode(BTN_WAYPOINT, INPUT_PULLUP);\n  pinMode(LED_STATUT, OUTPUT);\n\n  // SD\n  if (SD.begin(SD_CS)) {\n    creerFichierGPX();\n  } else {\n    Serial.println("SD non trouv\xe9e !");\n  }\n\n  Serial.println("GPS Tracker EduKit pr\xeat !");\n}\n\nvoid loop() {\n  // Lire donn\xe9es GPS\n  while (gpsSerial.available()) {\n    gps.encode(gpsSerial.read());\n  }\n\n  // LED clignote = actif, fixe = pas de fix\n  if (gps.location.isValid()) {\n    digitalWrite(LED_STATUT, (millis() / 500) % 2);\n  } else {\n    digitalWrite(LED_STATUT, (millis() / 100) % 2); // Clignotement rapide = recherche\n  }\n\n  // Enregistrer un point toutes les 5 secondes (si fix GPS)\n  if (gps.location.isValid() && millis() - dernierEnreg >= INTERVALLE_ENREG) {\n    dernierEnreg = millis();\n    float lat = gps.location.lat();\n    float lon = gps.location.lng();\n    DateTime now = rtc.now();\n\n    // Calculer distance depuis dernier point\n    if (latPrec != 0) {\n      distTotale += distanceMetres(latPrec, lonPrec, lat, lon);\n    }\n    latPrec = lat; lonPrec = lon;\n\n    // Enregistrer dans le GPX\n    ajouterPointGPX(lat, lon, bmp.readAltitude(1013.25), now);\n\n    Serial.print(lat, 6); Serial.print(",");\n    Serial.print(lon, 6); Serial.print(",");\n    Serial.println(gps.speed.kmph());\n  }\n\n  // Bouton waypoint\n  if (digitalRead(BTN_WAYPOINT) == LOW) {\n    delay(50); // Anti-rebond\n    if (digitalRead(BTN_WAYPOINT) == LOW && gps.location.isValid()) {\n      ajouterWaypoint(gps.location.lat(), gps.location.lng(), nbWaypoints + 1);\n      // Bip de confirmation (si buzzer connect\xe9 sur D6)\n      Serial.print("Waypoint "); Serial.print(nbWaypoints); Serial.println(" enregistr\xe9 !");\n      while (digitalRead(BTN_WAYPOINT) == LOW); // Attendre rel\xe2chement\n    }\n  }\n\n  afficherOLED();\n  delay(200);\n}\n'})}),"\n",(0,r.jsx)(e.hr,{}),"\n",(0,r.jsx)(e.h2,{id:"-visualiser-ta-trace-sur-google-earth",children:"\ud83d\udccd Visualiser ta trace sur Google Earth"}),"\n",(0,r.jsxs)(e.ol,{children:["\n",(0,r.jsx)(e.li,{children:"Retire la carte SD du tracker"}),"\n",(0,r.jsxs)(e.li,{children:["Copie le fichier ",(0,r.jsx)(e.code,{children:".gpx"})," sur ton ordinateur"]}),"\n",(0,r.jsxs)(e.li,{children:["Ouvre ",(0,r.jsx)(e.strong,{children:"Google Earth"})," \u2192 Fichier \u2192 Ouvrir \u2192 s\xe9lectionne le ",(0,r.jsx)(e.code,{children:".gpx"})]}),"\n",(0,r.jsx)(e.li,{children:"Ta trace appara\xeet en rouge sur la carte !"}),"\n"]}),"\n",(0,r.jsxs)(e.p,{children:["Ou utilise ",(0,r.jsx)(e.strong,{children:"GPSVisualizer.com"})," en ligne \u2014 colle le contenu du fichier et g\xe9n\xe8re une carte interactive."]}),"\n",(0,r.jsxs)(e.p,{children:["\u2705 ",(0,r.jsx)(e.strong,{children:"Code charg\xe9 !"})," \u2192 Passe aux ",(0,r.jsx)(e.strong,{children:(0,r.jsx)(e.a,{href:"./exercices",children:"exercices \u2192"})})]})]})}function p(n={}){const{wrapper:e}={...(0,o.R)(),...n.components};return e?(0,r.jsx)(e,{...n,children:(0,r.jsx)(c,{...n})}):c(n)}},8453:(n,e,t)=>{t.d(e,{R:()=>l,x:()=>a});var i=t(6540);const r={},o=i.createContext(r);function l(n){const e=i.useContext(o);return i.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function a(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(r):n.components||r:l(n.components),i.createElement(o.Provider,{value:e},n.children)}}}]);